SELECT start_date
FROM projects
ORDER BY start_date ASC;

SELECT DISTINCT u.user_name
FROM users u
WHERE EXISTS (
    SELECT 1 FROM assets a WHERE a.upload_user_id = u.user_id AND a.project_id = 1
) AND EXISTS (
    SELECT 1 FROM revisions r WHERE r.user_id = u.user_id AND r.project_id = 1
);

SELECT project_id, project_name
FROM projects
WHERE status = 'in progress';

SELECT COUNT(*) AS total_deliverables
FROM deliverables
WHERE project_id = 1;
